module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const n = (v) => { const x = parseFloat(v); return Number.isFinite(x) ? x : 0; };
const tp = n(args.tp), fp = n(args.fp), fn = n(args.fn), tn = n(args.tn);
const pos = esc(args.pos || 'Positive'), neg = esc(args.neg || 'Negative');
const okColor = args.color_ok || '#22c55e';
const errColor = args.color_err || '#ef4444';
const title = String(args.title || '').trim();
const cell = (v, ok, area) => `<div class="mdp-cm-cell ${ok ? 'ok' : 'err'}" style="grid-area:${area}">${v}</div>`;
const titleHtml = title ? `<div class="mdp-cm-title">${esc(title)}</div>` : '';
let html = `\n\n<div class="mdp-mod-confusionmatrix" style="--cm-ok:${okColor}; --cm-err:${errColor};">${titleHtml}<div class="mdp-cm-grid">` +
  `<div class="mdp-cm-corner" style="grid-area:corner"></div>` +
  `<div class="mdp-cm-axis mdp-cm-axis-x" style="grid-area:axisx">Predicted</div>` +
  `<div class="mdp-cm-col" style="grid-area:colp">${pos}</div><div class="mdp-cm-col" style="grid-area:coln">${neg}</div>` +
  `<div class="mdp-cm-axis mdp-cm-axis-y" style="grid-area:axisy"><span>Actual</span></div>` +
  `<div class="mdp-cm-row" style="grid-area:rowp">${pos}</div>${cell(tp, true, 'tp')}${cell(fn, false, 'fn')}` +
  `<div class="mdp-cm-row" style="grid-area:rown">${neg}</div>${cell(fp, false, 'fp')}${cell(tn, true, 'tn')}` +
  `</div>`;
if (String(args.metrics) === 'true') {
  const acc = (tp + tn) / ((tp + tn + fp + fn) || 1);
  const prec = tp / ((tp + fp) || 1);
  const rec = tp / ((tp + fn) || 1);
  const f1 = (2 * prec * rec) / ((prec + rec) || 1);
  const pc = (x) => (x * 100).toFixed(1) + '%';
  html += `<div class="mdp-cm-metrics">` +
    `<span><b>Accuracy</b> ${pc(acc)}</span>` +
    `<span><b>Precision</b> ${pc(prec)}</span>` +
    `<span><b>Recall</b> ${pc(rec)}</span>` +
    `<span><b>F1</b> ${f1.toFixed(3)}</span></div>`;
}
html += `</div>\n\n`;
return html;
